model.behavior:
AUCTION = (
  START ;
  SET_SENDER ;
  BIDDING ; 
  WITHDRAW ;
  NEXT_DAY
),

START = startAuction + !startAuction,
SET_SENDER = setSender + !setSender,
BIDDING = bid_first(20).bid_replace(30) + !bid_first(20),
WITHDRAW = withdraw(20) + !withdraw(20),
NEXT_DAY = nextDay.AUCTION + !nextDay.END,

END = end_fail + end_win.Delta
